Take a look at [this example](http://jsfiddle.net/Mottie/abkNM/794/) which is only for the zebra widget, but is essentially the same code for any widget.

The `activate` callback for jQuery UI tabs is used to either initialize tablesorter or update the widgets:

```js
var tablesorterOptions = {
    theme: 'blue',
    widgets: ["zebra"]
};

$("#tabs").tabs({
    create: function (event, ui) {
        var $t = ui.panel.find('table');
        if ($t.length) {
            $t.tablesorter(tablesorterOptions);
        }
    },
    activate: function (event, ui) {
        var $t = ui.newPanel.find('table');
        if ($t.length) {
            if ($t[0].config) {
                $t.trigger('applyWidgets');
            } else {
                $t.tablesorter(tablesorterOptions);
            }
        }
    }
});
```

Ahhh, in your [load callback function](http://api.jquery.com/load/#callback-function), you'll need to trigger an ["update" method](http://mottie.github.io/tablesorter/docs/#update):

```js
$('#table0').load('content/table0.php', function(){
    $('#table0').trigger('update');
});
```

